package tests;import base.BaseTest;import pages.CocineroPage;import pages.LoginPage;import org.junit.jupiter.api.Assertions;import org.junit.jupiter.api.Test;import org.openqa.selenium.WebDriver;import org.openqa.selenium.chrome.ChromeDriver;public class HP04MarcarPedidoEntregadoTest extends BaseTest {    @Test    void cocineroMarcaPedidoComoEntregado() {        try {            System.out.println("Ejecutando HP-04: Marcar pedido como entregado");            LoginPage loginPage = new LoginPage(driver);            loginPage.abrirLogin();            loginPage.iniciarSesion("cocinero", "123");            Thread.sleep(3000);            CocineroPage cocineroPage = new CocineroPage(driver);            int botonesAntes = cocineroPage.cantidadBotonesMarcarComoEntregado();            Assertions.assertTrue(                    botonesAntes > 0,                    "No existe ningún pedido en preparación para marcar como entregado."            );            cocineroPage.marcarComoEntregado();            Thread.sleep(3000);            int botonesDespues = cocineroPage.cantidadBotonesMarcarComoEntregado();            Assertions.assertTrue(                    botonesDespues < botonesAntes,                    "El pedido no fue marcado como entregado correctamente."            );            System.out.println("HP-04 ejecutado correctamente.");        } catch (Exception e) {            Assertions.fail("Error en HP-04: " + e.getMessage());        }    }}